// Time:  O(n^2 * k)
// Space: O(n^2 * k)

// dp
class Solution {
public:
    int longestPalindromicSubsequence(string s, int k) {
        vector<vector<vector<int>>> dp(size(s), vector<vector<int>>(size(s), vector<int>(k + 1)));
        for (int i = 0; i < size(s); ++i) {
            for (int x = 0; x <= k; ++x) {
                dp[i][i][x] = 1;
            }
        }
        for (int i = size(s) - 2; i >= 0; --i) {
            for (int j = i + 1; j < size(s); ++j) {
                for (int x = 0; x <= k; ++x) {
                    if (s[i] == s[j]) {
                        dp[i][j][x] = dp[i + 1][j - 1][x] + 2;
                    } else {
                        dp[i][j][x] = max(dp[i + 1][j][x], dp[i][j - 1][x]);
                        const int diff = abs(s[i] - s[j]);
                        const int c = min(diff, 26 - diff);
                        if (x >= c) {
                            dp[i][j][x] = max(dp[i][j][x], dp[i + 1][j - 1][x - c] + 2);
                        }
                    }
                }
            }
        }
        return dp[0][size(s) - 1][k];
    }
};

# Time:  O(n^2 * k)
# Space: O(n^2 * k)

# dp
class Solution(object):
    def longestPalindromicSubsequence(self, s, k):
        """
        :type s: str
        :type k: int
        :rtype: int
        """
        dp = [[[1 if i == j else 0 for _ in xrange(k+1)] for j in xrange(len(s))] for i in xrange(len(s))]
        for i in reversed(xrange(len(s)-1)):
            for j in xrange(i+1, len(s)):
                for x in xrange(k+1):
                    if s[i] == s[j]:
                        dp[i][j][x] = dp[i+1][j-1][x]+2
                    else:
                        dp[i][j][x] = max(dp[i+1][j][x], dp[i][j-1][x])
                        diff = abs(ord(s[i])-ord(s[j]))
                        c = min(diff, 26-diff)
                        if x >= c:
                            dp[i][j][x] = max(dp[i][j][x], dp[i+1][j-1][x-c]+2)
        return dp[0][-1][k]
